// AI Documentation: This was largely generated by AI. I provided my own code from the blockchain assignment and AGENTS.md as the style guide so it mostly matches what we covered in class.

const strBaseUrl = 'http://localhost:8000/api/'

// Function to load all the data into tables
function loadData() {
    // View Jobs
    fetch(strBaseUrl + 'jobs')
        .then(result => {
            if (result.ok) {
                return result.json()
            } else {
                throw new Error(result.status)
            }
        })
        .then(data => {
            let arrJobs = data.message
            document.querySelector('#tblJobsBody').innerHTML = ''
            arrJobs.forEach(objJob => {
                document.querySelector('#tblJobsBody').innerHTML += `<tr><td>${objJob.intJobID}</td><td>${objJob.strCompany}</td><td>${objJob.strTitle}</td><td>${objJob.strStartDate}</td><td>${objJob.strEndDate}</td></tr>`
            })
        })
        .catch(error => {
            console.error("Error loading jobs:", error)
        })

    // View Responsibilities
    fetch(strBaseUrl + 'responsibilities')
        .then(result => {
            if (result.ok) {
                return result.json()
            } else {
                throw new Error(result.status)
            }
        })
        .then(data => {
            let arrResp = data.message
            document.querySelector('#tblRespBody').innerHTML = ''
            arrResp.forEach(objResp => {
                document.querySelector('#tblRespBody').innerHTML += `<tr><td>${objResp.intRespID}</td><td>${objResp.intJobID}</td><td>${objResp.strDescription}</td></tr>`
            })
        })
        .catch(error => {
            console.error("Error loading responsibilities:", error)
        })

    // View Skills
    fetch(strBaseUrl + 'skills')
        .then(result => {
            if (result.ok) {
                return result.json()
            } else {
                throw new Error(result.status)
            }
        })
        .then(data => {
            let arrSkills = data.message
            document.querySelector('#tblSkillsBody').innerHTML = ''
            arrSkills.forEach(objSkill => {
                document.querySelector('#tblSkillsBody').innerHTML += `<tr><td>${objSkill.intSkillID}</td><td>${objSkill.strCategory}</td><td>${objSkill.strSkillName}</td></tr>`
            })
        })
        .catch(error => {
            console.error("Error loading skills:", error)
        })

    // View Certifications
    fetch(strBaseUrl + 'certifications')
        .then(result => {
            if (result.ok) {
                return result.json()
            } else {
                throw new Error(result.status)
            }
        })
        .then(data => {
            let arrCerts = data.message
            document.querySelector('#tblCertsBody').innerHTML = ''
            arrCerts.forEach(objCert => {
                document.querySelector('#tblCertsBody').innerHTML += `<tr><td>${objCert.intCertID}</td><td>${objCert.strName}</td><td>${objCert.strIssuer}</td><td>${objCert.strDateEarned}</td></tr>`
            })
        })
        .catch(error => {
            console.error("Error loading certifications:", error)
        })

    // View Awards
    fetch(strBaseUrl + 'awards')
        .then(result => {
            if (result.ok) {
                return result.json()
            } else {
                throw new Error(result.status)
            }
        })
        .then(data => {
            let arrAwards = data.message
            document.querySelector('#tblAwardsBody').innerHTML = ''
            arrAwards.forEach(objAward => {
                document.querySelector('#tblAwardsBody').innerHTML += `<tr><td>${objAward.intAwardID}</td><td>${objAward.strTitle}</td><td>${objAward.strDateReceived}</td><td>${objAward.strDescription}</td></tr>`
            })
        })
        .catch(error => {
            console.error("Error loading awards:", error)
        })
}

// Initial load
loadData()

// Saving a Job
document.querySelector('#btnSaveJob').addEventListener('click', () => {
    let strCompany = document.querySelector('#txtCompany').value.trim()
    let strTitle = document.querySelector('#txtTitle').value.trim()
    let strStartDate = document.querySelector('#txtStartDate').value.trim()
    let strEndDate = document.querySelector('#txtEndDate').value.trim()

    let blnError = false

    if (!strCompany || !strTitle || !strStartDate || !strEndDate) {
        blnError = true
    }

    if (blnError == false) {
        fetch(strBaseUrl + 'jobs', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ strCompany: strCompany, strTitle: strTitle, strStartDate: strStartDate, strEndDate: strEndDate })
        })
            .then(result => {
                if (result.ok || result.status == 201) {
                    return result.json()
                } else {
                    throw new Error(result.status)
                }
            })
            .then(data => {
                if (data.outcome == "success") {
                    Swal.fire({
                        title: "Success",
                        text: data.message,
                        icon: "success",
                        timer: 1500
                    })

                    // Clearing the boxes
                    document.querySelector('#txtCompany').value = ''
                    document.querySelector('#txtTitle').value = ''
                    document.querySelector('#txtStartDate').value = ''
                    document.querySelector('#txtEndDate').value = ''

                    // Refresh data
                    loadData()
                } else {
                    Swal.fire({
                        title: "Something went wrong",
                        icon: "error",
                        text: data.message
                    })
                }
            })
            .catch(error => {
                Swal.fire({
                    title: "Error",
                    icon: "error",
                    text: "Couldnt save the job."
                })
            })
    } else {
        Swal.fire({
            title: "Empty Fields",
            icon: "error",
            text: "You have to fill out all the fields."
        })
    }
})

